353	export function setThreadBranch(
354	  state: AppState,
355	  threadId: ThreadId,
356	  branch: string | null,
357	  worktreePath: string | null,
358	): AppState {
359	  const threads = updateThread(state.threads, threadId, (t) => {
360	    if (t.branch === branch && t.worktreePath === worktreePath) return t;
361	    const cwdChanged = t.worktreePath !== worktreePath;
362	    return {
363	      ...t,
364	      branch,
365	      worktreePath,
366	      ...(cwdChanged ? { session: null } : {}),
367	    };
368	  });
369	  return threads === state.threads ? state : { ...state, threads };
370	}
