/**
 * Theme definitions for T3 Code.
 *
 * Each theme defines a complete color palette, font family, and font size.
 * Themes are applied as CSS custom properties on the document root by the web app.
 */

export interface ThemeColors {
  readonly background: string;
  readonly foreground: string;
  readonly accent: string;
  readonly sidebar: string;
  readonly editor: string;
  readonly terminal: string;
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colors: ThemeColors;
  readonly fontFamily: string;
  readonly fontSize: number;
}

const DEFAULT_FONT_FAMILY =
  '"DM Sans", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif';

const T3_DARK: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  colors: {
    background: "#0c0c0d",
    foreground: "#f5f5f5",
    accent: "#3b82f6",
    sidebar: "#111113",
    editor: "#0c0c0d",
    terminal: "#090909",
    statusBar: "#111113",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: 14,
};

const T3_LIGHT: Theme = {
  id: "t3-light",
  name: "T3 Light",
  colors: {
    background: "#ffffff",
    foreground: "#1c1c1e",
    accent: "#2563eb",
    sidebar: "#f5f5f7",
    editor: "#ffffff",
    terminal: "#fafafa",
    statusBar: "#f0f0f2",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: 14,
};

const T3_MIDNIGHT: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  colors: {
    background: "#0b1121",
    foreground: "#c9d1d9",
    accent: "#7c3aed",
    sidebar: "#0d1529",
    editor: "#0b1121",
    terminal: "#080e1a",
    statusBar: "#0f1830",
  },
  fontFamily: DEFAULT_FONT_FAMILY,
  fontSize: 14,
};

const BUILT_IN_THEMES: readonly Theme[] = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

const themeMap = new Map<string, Theme>(
  BUILT_IN_THEMES.map((theme) => [theme.id, theme]),
);

/** The default theme, guaranteed to exist. */
export const DEFAULT_THEME: Theme = T3_DARK;

/** Return a single theme by ID, or `undefined` if not found. */
export function getTheme(id: string): Theme | undefined {
  return themeMap.get(id);
}

/** Return all available built-in themes. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/**
 * Determine whether a theme is considered "dark" based on the perceived
 * luminance of its background color (expects a 6-digit hex like `"#0c0c0d"`).
 */
export function isThemeDark(theme: Theme): boolean {
  const hex = theme.colors.background.replace("#", "");
  const r = Number.parseInt(hex.substring(0, 2), 16);
  const g = Number.parseInt(hex.substring(2, 4), 16);
  const b = Number.parseInt(hex.substring(4, 6), 16);
  // ITU-R BT.601 perceived luminance
  return (0.299 * r + 0.587 * g + 0.114 * b) / 255 < 0.5;
}

