import { isThemeDark, type Theme } from "@t3tools/shared/themes";

import { cn } from "~/lib/utils";
import { useTheme } from "../hooks/useTheme";

function ThemeSwatch({ theme }: { theme: Theme }) {
  return (
    <div className="flex shrink-0 overflow-hidden rounded-md border border-border/50">
      <div className="h-6 w-3.5" style={{ background: theme.colors.background }} />
      <div className="h-6 w-3.5" style={{ background: theme.colors.accent }} />
      <div className="h-6 w-3.5" style={{ background: theme.colors.sidebar }} />
    </div>
  );
}

export function ThemeSelector() {
  const { colorTheme, setColorTheme, availableThemes } = useTheme();

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Color theme">
      {availableThemes.map((t) => {
        const selected = colorTheme.id === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={selected}
            className={cn(
              "flex w-full items-center gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
              selected
                ? "border-primary/60 bg-primary/8 text-foreground"
                : "border-border bg-background text-muted-foreground hover:bg-accent",
            )}
            onClick={() => setColorTheme(t.id)}
          >
            <ThemeSwatch theme={t} />
            <span className="flex flex-1 flex-col">
              <span className="text-sm font-medium">{t.name}</span>
              <span className="text-xs opacity-70">
                {isThemeDark(t) ? "Dark theme" : "Light theme"}
              </span>
            </span>
            {selected ? (
              <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                Active
              </span>
            ) : null}
          </button>
        );
      })}
    </div>
  );
}

