import { useCallback, useEffect, useSyncExternalStore } from "react";
import { DEFAULT_THEME, getTheme, listThemes } from "@t3tools/shared/themes";

type ThemeMode = "light" | "dark" | "system";

type ThemeSnapshot = {
  mode: ThemeMode;
  systemDark: boolean;
  colorThemeId: string;
};

const MODE_STORAGE_KEY = "t3code:theme";
const COLOR_THEME_STORAGE_KEY = "t3code:color-theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

// ---------- External-store plumbing ----------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------- Persistence helpers ----------

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredMode(): ThemeMode {
  const raw = localStorage.getItem(MODE_STORAGE_KEY);
  if (raw === "light" || raw === "dark" || raw === "system") return raw;
  return "system";
}

function getStoredColorThemeId(): string {
  const raw = localStorage.getItem(COLOR_THEME_STORAGE_KEY);
  if (raw && getTheme(raw)) return raw;
  return DEFAULT_THEME.id;
}

// ---------- DOM application ----------

const THEME_CSS_PROPERTIES = [
  "--theme-background",
  "--theme-foreground",
  "--theme-accent",
  "--theme-sidebar",
  "--theme-editor",
  "--theme-terminal",
  "--theme-status-bar",
  "--theme-font-family",
  "--theme-font-size",
] as const;

function applyMode(mode: ThemeMode, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const isDark = mode === "dark" || (mode === "system" && getSystemDark());
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

function applyColorThemeProperties(themeId: string) {
  const theme = getTheme(themeId);
  const root = document.documentElement;

  if (!theme) {
    for (const prop of THEME_CSS_PROPERTIES) {
      root.style.removeProperty(prop);
    }
    return;
  }

  root.style.setProperty("--theme-background", theme.colors.background);
  root.style.setProperty("--theme-foreground", theme.colors.foreground);
  root.style.setProperty("--theme-accent", theme.colors.accent);
  root.style.setProperty("--theme-sidebar", theme.colors.sidebar);
  root.style.setProperty("--theme-editor", theme.colors.editor);
  root.style.setProperty("--theme-terminal", theme.colors.terminal);
  root.style.setProperty("--theme-status-bar", theme.colors.statusBar);
  root.style.setProperty("--theme-font-family", theme.fontFamily);
  root.style.setProperty("--theme-font-size", `${theme.fontSize}px`);
}

// Apply immediately on module load to prevent flash
applyMode(getStoredMode());
applyColorThemeProperties(getStoredColorThemeId());

// ---------- Snapshot / subscription ----------

function getSnapshot(): ThemeSnapshot {
  const mode = getStoredMode();
  const systemDark = mode === "system" ? getSystemDark() : false;
  const colorThemeId = getStoredColorThemeId();

  if (
    lastSnapshot &&
    lastSnapshot.mode === mode &&
    lastSnapshot.systemDark === systemDark &&
    lastSnapshot.colorThemeId === colorThemeId
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { mode, systemDark, colorThemeId };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStoredMode() === "system") applyMode("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === MODE_STORAGE_KEY) {
      applyMode(getStoredMode(), true);
      emitChange();
    }
    if (e.key === COLOR_THEME_STORAGE_KEY) {
      applyColorThemeProperties(getStoredColorThemeId());
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------- Hook ----------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const mode = snapshot.mode;

  const resolvedTheme: "light" | "dark" =
    mode === "system" ? (snapshot.systemDark ? "dark" : "light") : mode;

  const setTheme = useCallback((next: ThemeMode) => {
    localStorage.setItem(MODE_STORAGE_KEY, next);
    applyMode(next, true);
    emitChange();
  }, []);

  const colorTheme = getTheme(snapshot.colorThemeId) ?? DEFAULT_THEME;
  const availableThemes = listThemes();

  const setColorTheme = useCallback((id: string) => {
    if (!getTheme(id)) return;
    localStorage.setItem(COLOR_THEME_STORAGE_KEY, id);
    applyColorThemeProperties(id);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyMode(mode);
  }, [mode]);

  useEffect(() => {
    applyColorThemeProperties(snapshot.colorThemeId);
  }, [snapshot.colorThemeId]);

  return {
    /** Current mode preference: "light" | "dark" | "system". */
    theme: mode,
    /** Set the mode preference. */
    setTheme,
    /** Resolved mode after evaluating "system" against OS preference. */
    resolvedTheme,
    /** The active color theme object. */
    colorTheme,
    /** Switch color theme by ID. */
    setColorTheme,
    /** All available color themes. */
    availableThemes,
  } as const;
}

